// Strings are Objects, usually holding text like passwords, names, or file paths.
String greeting = "Welcome to the system.";

// Immutability rule: This does NOT change the original string.
// It destroys the old one and creates a brand new one in memory!
greeting = greeting + " User 1";

// Example 1: Standard literal creation
String playerOne = "Batman";

// Example 2: Proving the VIP Pool memory reuse
String playerTwo = "Batman";
// If we compare memory addresses using ==, it returns TRUE!
System.out.println(playerOne == playerTwo);

// Example 1: Forcing a new memory allocation
String secureToken = new String("Alpha-77");

// Example 2: Proving the memory bypass
String poolToken = "Alpha-77";
// This returns FALSE! Even though the text is the same, they live in different RAM locations.
System.out.println(secureToken == poolToken);

// Example 1: A multi-line UI message
String welcomeMenu = """
    --- MAIN MENU ---
    1. Start Game
    2. Options
    3. Quit
    """;

// Example 2: Formatting a JSON data payload
String jsonPayload = """
    {
        "username": "admin",
        "status": "active"
    }
    """;

// Example 1: Using StringBuilder (The fast, standard choice)
StringBuilder fastBoard = new StringBuilder("Bat");
fastBoard.append("-Man");
System.out.println(fastBoard.toString()); // Prints: Bat-Man

// Example 2: Using StringBuffer (The thread-safe choice)
StringBuffer secureBoard = new StringBuffer("System ");
secureBoard.append("Online"); // Safe for multiple background threads to edit at once

// Example 1: Assembling a String from raw parts
char[] rawLetters = {'G', 'o', 't', 'h', 'a', 'm'};
String assembledCity = new String(rawLetters);

// Example 2: Extracting the array back out of a String
String password = "Secret";
char[] extractedArray = password.toCharArray();
// Now we can scramble the array for security!
extractedArray[0] = '*';

String email = "usman@student.uok.edu.pk";

// 1. .length() - Returns the total number of characters
int size = email.length(); // 24

// 2. .charAt() - Finds the letter at a specific index
char firstLetter = email.charAt(0); // 'u'

// 3. .contains() - Checks if a sequence exists (Returns boolean)
boolean isStudent = email.contains("student"); // true

// 4. .indexOf() - Finds the exact numerical position of a character
int atSymbolIndex = email.indexOf('@'); // 5

String data = "Usman:SoftwareEngineering:Karachi";

// 1. .substring(start, end) - Extracts a chunk of text
// Grabs characters from index 0 up to (but NOT including) index 5
String name = data.substring(0, 5); // "Usman"

// 2. .substring(start) - Grabs everything from the start point to the very end
String location = data.substring(26); // "Karachi"

// 3. .split(delimiter) - Chops the string into a String[] array
String[] parts = data.split(":");
System.out.println(parts[1]); // "SoftwareEngineering"

String rawInput = "   hello WORLD   ";

// 1. .trim() - Destroys accidental spaces at the start and end
String clean = rawInput.trim(); // "hello WORLD"

// 2. .toUpperCase() & .toLowerCase() - Forces case formatting
String upper = clean.toUpperCase(); // "HELLO WORLD"

// 3. .replace() - Swaps specific characters or words
String fixed = upper.replace("WORLD", "USMAN"); // "HELLO USMAN"

String password = "admin123";
String userInput = new String("admin123");

// WRONG: This checks if they are the exact same object in RAM (Returns FALSE)
if (password == userInput) { ... }

// RIGHT: This checks if the actual letters match (Returns TRUE)
if (password.equals(userInput)) { ... }

// BONUS: Ignores capital/lowercase differences (Returns TRUE for "ADMIN123")
if (password.equalsIgnoreCase("ADMIN123")) { ... }

String ageText = "20";
String priceText = "99.99";

// 1. Integer.parseInt() - Converts text to whole numbers
int realAge = Integer.parseInt(ageText);
System.out.println(realAge + 5); // Correctly outputs 25

// 2. Double.parseDouble() - Converts text to decimals
double realPrice = Double.parseDouble(priceText);

// 3. String.valueOf() - The Reverse! Converts math back into text
String booleanText = String.valueOf(true); // "true"

String username = "Usman";
String emptySpace = "   ";

// 1. .length() - Returns the int count of characters
int size = username.length(); // Returns 5

// 2. .isEmpty() - Only true if length is exactly 0
boolean noData = emptySpace.isEmpty(); // Returns FALSE (Spaces count as characters!)

// 3. .isBlank() (Java 11+) - True if empty OR only contains spaces
boolean isGhost = emptySpace.isBlank(); // Returns TRUE

String email = "usman@gmail.com";

// 1. .charAt(index) - What letter is at position 0?
char firstLetter = email.charAt(0); // Returns 'u'

// 2. .indexOf(String) - At what position does '@' start?
int atSymbol = email.indexOf("@"); // Returns 5

// 3. .lastIndexOf(String) - Finds the LAST occurrence (reads right-to-left)
int lastDot = email.lastIndexOf("."); // Returns 11

// 4. .contains(String) - Simple true/false check
boolean isGmail = email.contains("gmail"); // Returns TRUE

String record = "ID-9942-ACTIVE";

// 1. .substring(startIndex) - Grabs from index to the end
String status = record.substring(8); // Returns "ACTIVE"

// 2. .substring(startIndex, endIndex) - Grabs a specific chunk
// IMPORTANT: Includes index 3, but STOPS at index 7!
String idNumber = record.substring(3, 7); // Returns "9942"

String csvData = "Usman,Karachi,SoftwareEngineering";

// 1. .split(delimiter) - Chops text into an array based on a separator
String[] parts = csvData.split(",");
System.out.println(parts[1]); // Prints "Karachi"

// 2. String.join() (Java 8+) - Glues pieces together with a separator
String glued = String.join(" | ", "Java", "C++", "Python");
// Returns "Java | C++ | Python"

String dbPassword = "Admin123";
String userInput = new String("Admin123");

// WRONG: Checks memory addresses, not text
boolean isMatch1 = (dbPassword == userInput); // FALSE

// RIGHT: Checks the exact characters safely
boolean isMatch2 = dbPassword.equals(userInput); // TRUE

// FORGIVING: Ignores capital/lowercase rules
boolean isMatch3 = dbPassword.equalsIgnoreCase("admin123"); // TRUE

String messyInput = "   usman@UOK.edu.pk   ";

// 1. .trim() (Legacy) - Strips basic ASCII spaces
String legacyClean = messyInput.trim(); 

// 2. .strip() (Modern Java 11+) - Strips ALL Unicode invisible characters
String modernClean = messyInput.strip(); 

// 3. .toLowerCase() - Forces standard casing for databases
String finalEmail = modernClean.toLowerCase();

// METHOD CHAINING: Do it all in one line!
String fastClean = messyInput.strip().toLowerCase();

String dialogue = "I hate bugs. Bugs are the worst.";

// 1. .replace(old, new) - Swaps exact text (Case-Sensitive!)
String fixed = dialogue.replace("hate", "love"); 
// "I love bugs. Bugs are the worst."

// 2. .replaceAll(regex, new) - Uses Regular Expressions
// This RegEx [Bb]ugs means "Find 'Bugs' OR 'bugs'"
String safe = dialogue.replaceAll("[Bb]ugs", "features");
// "I hate features. features are the worst."

int score = 100;
boolean isActive = true;

// 1. String.valueOf() - The safest way to turn anything into text
String scoreText = String.valueOf(score); // "100"
String activeText = String.valueOf(isActive); // "true"

// 2. .toCharArray() - Shatters the String into primitive bytes/chars
String secret = "Code";
char[] letters = secret.toCharArray(); // ['C', 'o', 'd', 'e']

String file = "report.pdf";

// 1. .startsWith() & .endsWith() - Boundary checks
boolean isPDF = file.endsWith(".pdf"); // TRUE

// 2. .compareTo() - Alphabetical sorting (Dictionary Order)
String word1 = "Apple";
String word2 = "Banana";
// Returns a NEGATIVE number because 'A' comes before 'B'
int sortValue = word1.compareTo(word2); 

// 3. .matches(regex) - Advanced security validation
String pinCode = "1234";
// RegEx: "^[0-9]{4}$" means "Exactly 4 numbers from start to finish"
boolean isValidPin = pinCode.matches("^[0-9]{4}$"); // TRUE

// 1. String.format() - Injecting variables into clean templates
String hero = "Batman";
int level = 50;
double health = 98.5;

// The %.1f tells Java to round the decimal to exactly 1 place!
String profile = String.format("Player %s is level %d with %.1f HP.", hero, level, health);
System.out.println(profile);

// 2. .concat() - The strict alternative to the '+' operator
String base = "Bat";
String full = base.concat("man"); // "Batman"

// 3. .repeat() (Java 11+) - Instant multiplication without loops
String echo = "Hello ".repeat(3); // "Hello Hello Hello "

// 4. .getBytes() - Ripping text into raw network data
byte[] payload = "System Offline".getBytes();

String literal = "Code";           // Lives in the VIP Pool
String object = new String("Code"); // Forced into the Heap

// This prints FALSE because they live in different memory locations!
System.out.println(literal == object); 

// This prints TRUE because the letters are exactly the same!
System.out.println(literal.equals(object));

// You can use Unicode escape codes to print special global characters
String heart = "\u2764"; 

// Prints: I ❤ Java
System.out.println("I " + heart + " Java");

// If we didn't use \", Java would crash thinking the String ended early!
String dialogue = "The boss said, \"Get to work!\"\n\t- Management";

/* Output:
The boss said, "Get to work!"
    - Management
*/

String heapString = new String("Gotham"); // Stuck in regular RAM
String poolString = "Gotham";             // Safe in the VIP Pool

System.out.println(heapString == poolString); // false (Different addresses)

// THE OVERRIDE: Force the heap string to point to the VIP pool!
heapString = heapString.intern(); 

System.out.println(heapString == poolString); // true!

String email = "usman123@gmail.com";

// RegEx: "Start with letters/numbers, then @, then letters, then .com"
String emailPattern = "^[a-zA-Z0-9]+@[a-zA-Z]+\\.com$";

boolean isValid = email.matches(emailPattern);

System.out.println("Is email valid? " + isValid); // TRUE

// What you type in your IDE:
String hero = "Bat" + "man";

// What the Java Compiler secretly changes it to behind your back:
String hero = new StringBuilder("Bat").append("man").toString();

